"use client";
import { userSchema } from "@/lib/validations";
import { zodResolver } from "@hookform/resolvers/zod";
import { redirect, useRouter } from "next/navigation";
import React, { useState } from "react";
import { useForm } from "react-hook-form";
import z from "zod";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "../ui/form";

import { useNeedReceiptStore, useUserDataStore } from "@/store/userStore";
import { Input } from "../ui/input";
import { Button } from "../ui/button";
import { Toaster } from "../ui/sonner";
import { toast } from "sonner";

const KycForm = () => {
  const form = useForm<z.infer<typeof userSchema>>({
    resolver: zodResolver(userSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      contactNum: "",
    },
  });
  const { newData, saveData } = useUserDataStore();
  const onSubmit = (values: z.infer<typeof userSchema>) => {
    if (values.contactNum || values.firstName || values.lastName) {
      saveData(values);
      <Toaster position="bottom-right" duration={3} />;
      toast.message("User's information saved!");
    } else {
    }
  };

  const status = useNeedReceiptStore((state) => state.receiptStatus);

  return status === "No" ? (
    redirect("/")
  ) : (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(onSubmit)}
        className="bg-[#f7f5dc] shadow-md rounded px-8 pt-6 pb-8 mb-4"
        method="POST"
      >
        <p className="xs:text-xl sm:text-xl md:text-2xl lg:text-3xl py-4 capitalize">
          Please fill the form
        </p>
        <FormField
          control={form.control}
          name="firstName"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-sm md:text-md lg:text-lg text-[#5f5f5f]">
                First Name
              </FormLabel>
              <FormControl>
                <Input
                  // onChange={(e) => setFirstName(e.target.value)}
                  {...field}
                  type="text"
                  className="border-2 border-[#000]"
                  placeholder="First Name..."
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <FormField
          control={form.control}
          name="lastName"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-sm md:text-md lg:text-lg text-[#5f5f5f]">
                Last Name
              </FormLabel>
              <FormControl>
                <Input
                  // onChange={(e) => setLastName(e.target.value)}
                  {...field}
                  type="text"
                  className="border-2 border-[#000]"
                  placeholder="Last Name..."
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <FormField
          control={form.control}
          name="contactNum"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-sm md:text-md lg:text-lg text-[#5f5f5f]">
                Contact Number
              </FormLabel>
              <FormControl>
                <Input
                  // onChange={(e) => setcontactNum(parseInt(e.target.value))}
                  {...field}
                  type="number"
                  className="border-2 border-[#000]"
                  placeholder="Contact Number..."
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        {/* <Link
          rel="preload"
          href={"/cart"}
          className="py-2 px-4 rounded-md cursor-pointer text-white bg-[#216c58]"
        >
          Next
        </Link> */}
        <Button
          onClick={() => toast.message('sadads')}
          type="submit"
          className="w-full cursor-pointer"
        >
          NEXT
        </Button>
      </form>
    </Form>
  );
};

export default KycForm;
